mapper.update:
UPDATE MEMBER
SET PASSWORD = #{password}
WHERE MEMBER_ID = #{memberId}

UPDATE MEMBER
    SET MEMBER_STATUS = #{memberStatus}
    WHERE MEMBER_ID = #{memberId}

